  1→using System.IO.Ports;
  2→using System.Text;
  3→
  4→namespace DiffTest
  5→{
  6→    /// <summary>
  7→    /// 바코드 라벨 생성 및 프린터 전송 서비스
  8→    /// FrmMain에서 분리된 독립 클래스
  9→    /// </summary>
 10→    public class BarcodeService
 11→    {
 12→        private readonly MeasureData _data;
 13→        private readonly SerialPort? _printerLH;
 14→        private readonly SerialPort? _printerRH;
 15→
 16→        public BarcodeService(MeasureData data, SerialPort? printerLH, SerialPort? printerRH)
 17→        {
 18→            _data = data;
 19→            _printerLH = printerLH;
 20→            _printerRH = printerRH;
 21→        }
 22→
 23→        /// <summary>
 24→        /// 바코드 라벨 출력 (OK)
 25→        /// VB 원본: 2D 바코드 포맷 + DIFF 평균값 출력
 26→        /// </summary>
 27→        public void BarcodePrint(string partNo, string partName, string serialNo, string side)
 28→        {
 29→            LogHelper.Instance.Log("Barcode", $"[OK] 출력 시작: side={side}, partNo={partNo}, serial={serialNo}");
 30→
 31→            try
 32→            {
 33→                var bs = BarcodeSettings.Instance;
 34→                MdbHelper.LoadBarcodeData();
 35→
 36→                // 2D 바코드 데이터 생성 (VB 원본 포맷)
 37→                // ZPL ^FH 명령이 _XX를 hex로 해석하므로 문자열 그대로 전송
 38→                const string RS = "_1e";   // Record Separator (^FH가 해석)
 39→                const string GS = "_1d";   // Group Separator (^FH가 해석)
 40→                const string EOT = "_04";  // End of Transmission (^FH가 해석)
 41→
 42→                string partNoClean = partNo.Replace("-", "");
 43→                string midSerial1 = serialNo.Length >= 8 ? serialNo.Substring(2, 6) : "";
 44→                string midSerial2 = serialNo.Length >= 15 ? serialNo.Substring(8, 7) : "";
 45→
 46→                string barcodeData = $"[)>{RS}06{GS}VPB30{GS}P{partNoClean}{GS}S{GS}E{GS}T{midSerial1}DA1SAA{midSerial2}{GS}M{GS}C{GS}{RS}{EOT}";
 47→
 48→                // DIFF 평균값 계산
 49→                string diffData = CalcDiffAverageString(side);
 50→
 51→                // 바코드 사이즈 (+2 VB 원본)
 52→                int barcodeSize = (int.TryParse(bs.BarcodeSize1, out var s1) ? s1 : 7) + 2;
 53→                int barcodeSize2 = int.TryParse(bs.BarcodeSize2, out var s2) ? s2 : 200;
 54→
 55→                // ZPL 생성
 56→                var sb = new StringBuilder();
 57→                sb.Append("^XA");
 58→                sb.Append($"^FO{bs.BarcodeX},{bs.BarcodeY}^BY5^BXN,{barcodeSize},{barcodeSize2},,,,^FH^FD{barcodeData}^FS");
 59→                sb.Append($"^FO{bs.SerialNoX},{bs.SerialNoY}^A0N,{bs.SerialNoH},{bs.SerialNoW}^FD{serialNo}^FS");
 60→                sb.Append($"^FO{bs.PartNoX},{bs.PartNoY}^A0N,{bs.PartNoH},{bs.PartNoW}^FD{partNo}^FS");
 61→                sb.Append($"^FO{bs.PartNameX},{bs.PartNameY}^A0N,{bs.PartNameH},{bs.PartNameW}^FD{partName}^FS");
 62→                sb.Append($"^FO{bs.CompanyX},{bs.CompanyY}^A0N,{bs.CompanyH},{bs.CompanyW}^FD{diffData}^FS");
 63→                sb.Append("^XZ");
 64→
 65→                string zpl = sb.ToString();
 66→                LogHelper.Instance.Log("Barcode", $"[OK] ZPL 생성: {zpl.Length}자, diffData={diffData}");
 67→
 68→                // 프린터 전송
 69→                if (side == "A" || side == "LH")
 70→                    SendToPrinter(_printerLH, zpl, "LH");
 71→                else if (side == "B" || side == "RH")
 72→                    SendToPrinter(_printerRH, zpl, "RH");
 73→            }
 74→            catch (Exception ex)
 75→            {
 76→                LogHelper.Instance.LogError("Barcode", $"[OK] 출력 오류: side={side}", ex);
 77→            }
 78→        }
 79→
 80→        /// <summary>
 81→        /// NG 바코드 라벨 출력
 82→        /// VB 원본: 바코드에 NG 접두어 + TQ 필드에 "NG" 출력
 83→        /// </summary>
 84→        public void BarcodePrintNG(string ngMessage, string partNo, string partName, string serialNo, string side)
 85→        {
 86→            LogHelper.Instance.Log("Barcode", $"[NG] 출력 시작: side={side}, partNo={partNo}, serial={serialNo}, msg={ngMessage}");
 87→
 88→            try
 89→            {
 90→                var bs = BarcodeSettings.Instance;
 91→                MdbHelper.LoadBarcodeData();
 92→
 93→                // 바코드 데이터: NG + 시리얼 (VB 원본)
 94→                string barcodeData = "NG" + serialNo;
 95→
 96→                // 바코드 사이즈 (+2 VB 원본)
 97→                int barcodeSize = (int.TryParse(bs.BarcodeSize1, out var s1) ? s1 : 7) + 2;
 98→                int barcodeSize2 = int.TryParse(bs.BarcodeSize2, out var s2) ? s2 : 200;
 99→
100→                // ZPL 생성 (TQ 필드에 "NG" 추가)
101→                var sb = new StringBuilder();
102→                sb.Append("^XA");
103→                sb.Append($"^FO{bs.BarcodeX},{bs.BarcodeY}^BY5^BXN,{barcodeSize},{barcodeSize2},,,,^FH^FD{barcodeData}^FS");
104→                sb.Append($"^FO{bs.SerialNoX},{bs.SerialNoY}^A0N,{bs.SerialNoH},{bs.SerialNoW}^FD{serialNo}^FS");
105→                sb.Append($"^FO{bs.PartNoX},{bs.PartNoY}^A0N,{bs.PartNoH},{bs.PartNoW}^FD{partNo}^FS");
106→                sb.Append($"^FO{bs.PartNameX},{bs.PartNameY}^A0N,{bs.PartNameH},{bs.PartNameW}^FD{partName}^FS");
107→                sb.Append($"^FO{bs.CompanyX},{bs.CompanyY}^A0N,{bs.CompanyH},{bs.CompanyW}^FD{ngMessage}^FS");
108→                sb.Append($"^FO{bs.TqX},{bs.TqY}^A0N,{bs.TqH},{bs.TqW}^FDNG^FS");
109→                sb.Append("^XZ");
110→
111→                string zpl = sb.ToString();
112→                LogHelper.Instance.Log("Barcode", $"[NG] ZPL 생성: {zpl.Length}자");
113→
114→                // 프린터 전송
115→                if (side == "A" || side == "LH")
116→                    SendToPrinter(_printerLH, zpl, "LH");
117→                else if (side == "B" || side == "RH")
118→                    SendToPrinter(_printerRH, zpl, "RH");
119→            }
120→            catch (Exception ex)
121→            {
122→                LogHelper.Instance.LogError("Barcode", $"[NG] 출력 오류: side={side}", ex);
123→            }
124→        }
125→
126→        /// <summary>
127→        /// 강제 라벨 출력 (FrmBarcode에서 호출)
128→        /// </summary>
129→        public void ManualBarcodePrint(string partNo, string partName, string serialNo, string side)
130→        {
131→            LogHelper.Instance.Log("Barcode", $"[Manual] 출력 시작: side={side}, partNo={partNo}, serial={serialNo}");
132→
133→            try
134→            {
135→                var bs = BarcodeSettings.Instance;
136→                MdbHelper.LoadBarcodeData();
137→
138→                // 2D 바코드 데이터 생성
139→                const string RS = "_1e";
140→                const string GS = "_1d";
141→                const string EOT = "_04";
142→
143→                string partNoClean = partNo.Replace("-", "");
144→                string midSerial1 = serialNo.Length >= 8 ? serialNo.Substring(2, 6) : "";
145→                string midSerial2 = serialNo.Length >= 15 ? serialNo.Substring(8, 7) : "";
146→
147→                string barcodeData = $"[)>{RS}06{GS}VPB30{GS}P{partNoClean}{GS}S{GS}E{GS}T{midSerial1}DA1SAA{midSerial2}{GS}M{GS}C{GS}{RS}{EOT}";
148→
149→                // 바코드 사이즈 (+2 VB 원본)
150→                int barcodeSize = (int.TryParse(bs.BarcodeSize1, out var s1) ? s1 : 7) + 2;
151→                int barcodeSize2 = int.TryParse(bs.BarcodeSize2, out var s2) ? s2 : 200;
152→
153→                // ZPL 생성
154→                var sb = new StringBuilder();
155→                sb.Append("^XA");
156→                sb.Append($"^FO{bs.BarcodeX},{bs.BarcodeY}^BY5^BXN,{barcodeSize},{barcodeSize2},,,,^FH^FD{barcodeData}^FS");
157→                sb.Append($"^FO{bs.SerialNoX},{bs.SerialNoY}^A0N,{bs.SerialNoH},{bs.SerialNoW}^FD{serialNo}^FS");
158→                sb.Append($"^FO{bs.PartNoX},{bs.PartNoY}^A0N,{bs.PartNoH},{bs.PartNoW}^FD{partNo}^FS");
159→                sb.Append($"^FO{bs.PartNameX},{bs.PartNameY}^A0N,{bs.PartNameH},{bs.PartNameW}^FD{partName}^FS");
160→                sb.Append($"^FO{bs.CompanyX},{bs.CompanyY}^A0N,{bs.CompanyH},{bs.CompanyW}^FD ^FS");  // 강제출력은 빈값
161→                sb.Append("^XZ");
162→
163→                string zpl = sb.ToString();
164→                LogHelper.Instance.Log("Barcode", $"[Manual] ZPL 생성: {zpl.Length}자");
165→
166→                // 프린터 전송
167→                if (side == "A" || side == "LH")
168→                    SendToPrinter(_printerLH, zpl, "LH");
169→                else if (side == "B" || side == "RH")
170→                    SendToPrinter(_printerRH, zpl, "RH");
171→            }
172→            catch (Exception ex)
173→            {
174→                LogHelper.Instance.LogError("Barcode", $"[Manual] 출력 오류: side={side}", ex);
175→            }
176→        }
177→
178→        /// <summary>
179→        /// DIFF 평균값 문자열 생성
180→        /// VB 원본: "F:{fwd}mm B:{bwd}mm D:{end}mm Lever:{lever}Kg"
181→        /// </summary>
182→        public string CalcDiffAverageString(string side)
183→        {
184→            try
185→            {
186→                double fwdSum = 0, bwdSum = 0, endSum = 0;
187→                int fwdCnt = 0, bwdCnt = 0, endCnt = 0;
188→
189→                for (int i = 0; i < 5; i++)
190→                {
191→                    if (!string.IsNullOrEmpty(_data.ValDiffFwd[i]) && double.TryParse(_data.ValDiffFwd[i], out double fv))
192→                    {
193→                        fwdSum += fv; fwdCnt++;
194→                    }
195→                    if (!string.IsNullOrEmpty(_data.ValDiffBwd[i]) && double.TryParse(_data.ValDiffBwd[i], out double bv))
196→                    {
197→                        bwdSum += bv; bwdCnt++;
198→                    }
199→                    if (!string.IsNullOrEmpty(_data.ValDiffEnd[i]) && double.TryParse(_data.ValDiffEnd[i], out double ev))
200→                    {
201→                        endSum += ev; endCnt++;
202→                    }
203→                }
204→
205→                string fwdAvg = fwdCnt > 0 ? (fwdSum / fwdCnt).ToString("F1") : "0.0";
206→                string bwdAvg = bwdCnt > 0 ? (bwdSum / bwdCnt).ToString("F1") : "0.0";
207→                string endAvg = endCnt > 0 ? (endSum / endCnt).ToString("F1") : "0.0";
208→
209→                string lever = (side == "A" || side == "RH")
210→                    ? _data.ValueLever.ToString("F1")
211→                    : _data.ValueLeverB.ToString("F1");
212→
213→                // WAV 사양은 각도(°) 표기, 그 외는 Kg 표기
214→                string optionType = (side == "A" || side == "LH") ? _data.OptionTypeA : _data.OptionTypeB;
215→                string leverUnit = optionType == "3-WAV" ? "°" : "Kg";
216→
217→                return $"F:{fwdAvg}mm B:{bwdAvg}mm D:{endAvg}mm Lever:{lever}{leverUnit}";
218→            }
219→            catch
220→            {
221→                return "";
222→            }
223→        }
224→
225→        /// <summary>
226→        /// 프린터로 ZPL 전송
227→        /// </summary>
228→        private void SendToPrinter(SerialPort? printer, string zpl, string printerName)
229→        {
230→            if (printer == null || !printer.IsOpen)
231→            {
232→                LogHelper.Instance.Log("Barcode", $"프린터 미연결: {printerName}");
233→                return;
234→            }
235→
236→            try
237→            {
238→                printer.Write(zpl);
239→                LogHelper.Instance.Log("Barcode", $"프린터 전송 완료: {printerName}, port={printer.PortName}");
240→            }
241→            catch (Exception ex)
242→            {
243→                LogHelper.Instance.LogError("Barcode", $"프린터 전송 오류: {printerName}", ex);
244→            }
245→        }
246→    }
247→}
