125→        /// <summary>
126→        /// 강제 라벨 출력
127→        /// </summary>
128→        private void btnManualPrint_Click(object sender, EventArgs e)
129→        {
130→            // 입력 검증
131→            if (cboPartNo.SelectedItem == null)
132→            {
133→                MessageBox.Show(this, "PartNo를 선택하세요.", "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
134→                return;
135→            }
136→            if (cboColor.SelectedItem == null)
137→            {
138→                MessageBox.Show(this, "Color를 선택하세요.", "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
139→                return;
140→            }
141→            if (!int.TryParse(txtLotStart.Text, out int lotStart) || lotStart < 1)
142→            {
143→                MessageBox.Show(this, "Lot 시작번호를 올바르게 입력하세요.", "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
144→                return;
145→            }
146→            if (!int.TryParse(txtQty.Text, out int qty) || qty < 1)
147→            {
148→                MessageBox.Show(this, "수량을 올바르게 입력하세요.", "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
149→                return;
150→            }
151→            if (cboPrinter.SelectedItem == null)
152→            {
153→                MessageBox.Show(this, "프린터를 선택하세요.", "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
154→                return;
155→            }
156→
157→            string partNo = cboPartNo.SelectedItem.ToString() ?? "";
158→            string colorCode = cboColor.SelectedItem.ToString() ?? "";
159→            string dateStr = dtpDate.Value.ToString("yyyyMMdd");
160→            string printer = cboPrinter.SelectedItem.ToString() ?? "LH";
161→            string side = printer == "LH" ? "B" : "A";
162→
163→            // PartName 조회
164→            string partName = SqlHelper.GetPartName(partNo);
165→
166→            // 수량만큼 출력
167→            for (int i = 0; i < qty; i++)
168→            {
169→                int lotNum = lotStart + i;
170→                // 시리얼번호: 날짜(8) + LOT번호(7) + PartNo
171→                string serialNo = dateStr + lotNum.ToString("0000000") + partNo;
172→
173→                // FrmMain의 BarcodePrint 호출
174→                _frmMain?.ManualBarcodePrint(partNo + colorCode, partName, serialNo, side);
175→            }
176→
177→            MessageBox.Show(this, $"{qty}장 출력 완료", "출력 완료", MessageBoxButtons.OK, MessageBoxIcon.Information);
178→        }
179→    }
